            short_greeks = {'delta': 0.0, 'gamma': 0.0, 'vega': 0.0}

            for greek_data, position in zip(greeks_list, positions):
                if position == 'long':
                    long_greeks['delta'] += greek_data['delta']
                    long_greeks['gamma'] += greek_data['gamma']
                    long_greeks['vega'] += greek_data['vega']
                elif position == 'short':
                    short_greeks['delta'] -= greek_data['delta']
                    short_greeks['gamma'] -= greek_data['gamma']
                    short_greeks['vega'] -= greek_data['vega']

            return {'long': long_greeks, 'short': short_greeks}

    def compute_greeks(self):
        greeks_list = []

        for option in self.options:
            model = BlackScholesMertonModel(option['s0'], option['k'], option['t'], option['r'])
            sigma = option.get('sigma', 0.2)  # Default volatility
            delta = model.delta(sigma)
            gamma = model.gamma(sigma)
            vega = model.vega(sigma)
            greeks_list.append({'delta': delta, 'gamma': gamma, 'vega': vega})

        return self.aggregate_greeks(greeks_list)

