#### Step 4: Desk Aggregation
If you have multiple portfolios (desks), aggregate the Greeks at the desk level.

```python
class Desk:
    def __init__(self, portfolios):
        self.portfolios = portfolios

    def compute_greeks(self):
        total_delta = sum([portfolio.compute_greeks()['total']['delta'] for portfolio in self.portfolios])
        total_gamma = sum([portfolio.compute_greeks()['total']['gamma'] for portfolio in self.portfolios])
        total_vega = sum([portfolio.compute_greeks()['total']['vega'] for portfolio in self.portfolios])

        return {'desk': {'delta': total_delta, 'gamma': total_gamma, 'vega': total_vega}

# Example usage
portfolios = [Portfolio(options=options_data), Portfolio(options=options_data)]
desk = Desk(portfolios)
greeks = desk.compute_greeks()

print(f"Desk Delta: {greeks['desk']['delta']:.4f}")
print(f"Desk Gamma: {greeks['desk']['gamma']:.4f}")
print(f"Desk Vega: {greeks['desk']['vega']:.4f}")
```

